1	package import_module
2	
3	import (
4		"context"
5		"encoding/json"
6		"fmt"
7		"reflect"
8		"regexp"
9		"sort"
10		"strings"
11		"sync"
12	
13		"github.com/port-experimental/port-cli/internal/api"
14		"github.com/port-experimental/port-cli/internal/auth"
15		"github.com/port-experimental/port-cli/internal/config"
16		"github.com/port-experimental/port-cli/internal/modules/export"
17	)
18	
19	// Module handles importing data to Port.
20	type Module struct {
21		client *api.Client
22	}
23	
24	// NewModule creates a new import module.
25	func NewModule(token *auth.Token, orgConfig *config.OrganizationConfig) *Module {
26		client := api.NewClient(api.ClientOpts{
27			Token:        token,
28			ClientID:     orgConfig.ClientID,
29			ClientSecret: orgConfig.ClientSecret,
30			APIURL:       orgConfig.APIURL,
31			Timeout:      0,
32		})
33		return &Module{
34			client: client,
35		}
36	}
37	
38	// Options represents import options.
39	// ProgressCallback is called to report import progress.
40	// phase is the current phase name, current is the number of items processed, total is the total count.
41	type ProgressCallback func(phase string, current, total int)
42	
43	// Options represents import options.
44	type Options struct {
45		InputPath              string
46		DryRun                 bool
47		SkipEntities           bool
48		SkipSystemBlueprints   bool // skip _* blueprint schemas and their entities
49		IncludeResources       []string
50		ExcludeBlueprints      []string // deep: exclude blueprint schema + all its resources
51		ExcludeBlueprintSchema []string // shallow: exclude only the blueprint schema, keep resources
52		Verbose                bool
53		ShowPagesPipeline      bool
54		ProgressCallback       ProgressCallback
55		LogCallback            func(string)
56	}
57	
58	// ValidationWarning represents a pre-import validation warning.
59	type ValidationWarning struct {
60		Type    string // "cycle", "missing_dependency", "protected_resource"
61		Message string
62		Details []string
63	}
64	
65	// Result represents the result of an import operation.
66	type Result struct {
67		Success             bool
68		Message             string
69		BlueprintsCreated   int
70		BlueprintsUpdated   int
71		EntitiesCreated     int
72		EntitiesUpdated     int
73		ScorecardsCreated   int
74		ScorecardsUpdated   int
75		ActionsCreated      int
76		ActionsUpdated      int
77		TeamsCreated        int
78		TeamsUpdated        int
79		UsersCreated        int
80		UsersUpdated        int
81		PagesCreated        int
82		PagesUpdated        int
83		IntegrationsUpdated int
84		Errors              []string
85		ErrorsByCategory    map[string][]string // Categorized errors for verbose output
86		Warnings            []ValidationWarning // Pre-import validation warnings
87		DiffResult          *DiffResult
88		SidebarPipeline     []string
89	}
90	
91	type SidebarPipelineOperation struct {
92		ResourceType string
93		Identifier   string
94		Folder       api.Folder
95		Page         api.Page
96	}
97	
98	type SidebarPipelineStep struct {
99		Operations []SidebarPipelineOperation
100	}
101	
102	// Execute performs the import operation.
103	func (m *Module) Execute(ctx context.Context, opts Options) (*Result, error) {
104		// Load data
105		loader := NewLoader()
106		data, err := loader.LoadData(opts.InputPath)
107		if err != nil {
108			return nil, fmt.Errorf("failed to load data: %w", err)
109		}
110	
111		// Apply blueprint exclusions before diffing/importing
112		applyDataExclusion(data, opts.ExcludeBlueprints, opts.ExcludeBlueprintSchema, opts.SkipSystemBlueprints)
113	
114		// Validate data
115		if err := loader.ValidateData(data); err != nil {
116			return nil, fmt.Errorf("validation failed: %w", err)
117		}
118	
119		// Diff validation (always enabled)
120		comparer := NewDiffComparer(m.client)
121		diffResult, err := comparer.Compare(ctx, data, opts)
122		if err != nil {
123			return nil, fmt.Errorf("diff comparison failed: %w", err)
124		}
125	
126		// Use diff result to filter data
127		data = diffResult.FilterData(data)
128	
129		sidebarPipeline := PlanSidebarPipeline(data.Folders, data.Pages)
130	
131		// Dry run - show what would happen
132		if opts.DryRun {
133			result := m.generateDryRunResult(data, diffResult, opts)
134			result.SidebarPipeline = DescribeSidebarPipeline(sidebarPipeline)
135			return result, nil
136		}
137	
138		// Import data using new reliable importer
139		importer := NewImporter(m.client)
140		if len(sidebarPipeline) > 0 && opts.LogCallback != nil && opts.ShowPagesPipeline {
141			opts.LogCallback("Proposed sidebar pipeline:")
142			for _, line := range DescribeSidebarPipeline(sidebarPipeline) {
143				opts.LogCallback(fmt.Sprintf("  %s", line))
144			}
145		}
146		result, err := importer.Import(ctx, data, opts)
147		if err != nil {
148			return nil, fmt.Errorf("import failed: %w", err)
149		}
150	
151		// Import permissions (blueprint and action permissions depend on resources existing)
152		importer.importPermissions(ctx, diffResult)
153	
154		// Merge any permission errors into result
155		result.Errors = importer.errors.ToStringSlice()
156	
157		result.Success = true
158		result.Message = "Successfully imported data"
159		result.DiffResult = diffResult
160		result.SidebarPipeline = DescribeSidebarPipeline(sidebarPipeline)
161		return result, nil
162	}
163	
164	// generateDryRunResult generates a dry run result with accurate predictions.
165	func (m *Module) generateDryRunResult(data *export.Data, diffResult *DiffResult, _ Options) *Result {
166		if diffResult != nil {
167			return &Result{
168				Success:             true,
169				Message:             "Validation passed (dry run - no changes applied)",
170				BlueprintsCreated:   len(diffResult.BlueprintsToCreate),
171				BlueprintsUpdated:   len(diffResult.BlueprintsToUpdate),
172				EntitiesCreated:     len(diffResult.EntitiesToCreate),
173				EntitiesUpdated:     len(diffResult.EntitiesToUpdate),
174				ScorecardsCreated:   len(diffResult.ScorecardsToCreate),
175				ScorecardsUpdated:   len(diffResult.ScorecardsToUpdate),
176				ActionsCreated:      len(diffResult.ActionsToCreate),
177				ActionsUpdated:      len(diffResult.ActionsToUpdate),
178				TeamsCreated:        len(diffResult.TeamsToCreate),
179				TeamsUpdated:        len(diffResult.TeamsToUpdate),
180				UsersCreated:        len(diffResult.UsersToCreate),
181				UsersUpdated:        len(diffResult.UsersToUpdate),
182				PagesCreated:        len(diffResult.PagesToCreate),
183				PagesUpdated:        len(diffResult.PagesToUpdate),
184				IntegrationsUpdated: len(diffResult.IntegrationsToUpdate),
185				DiffResult:          diffResult,
186			}
187		}
188	
189		return &Result{
190			Success:           true,
191			Message:           "Validation passed (dry run - no changes applied)",
192			BlueprintsCreated: len(data.Blueprints),
193			EntitiesCreated:   len(data.Entities),
194		}
195	}
