205	// shouldImport checks if a resource type should be imported.
206	func shouldImport(resourceType string, includeResources []string) bool {
207		if len(includeResources) == 0 {
208			return true
209		}
210		for _, r := range includeResources {
211			if r == resourceType {
212				return true
213			}
214		}
215		return false
216	}
