218	// cleanSystemFields removes system fields that shouldn't be sent to API.
219	func cleanSystemFields(resource map[string]interface{}, fieldsToRemove []string) map[string]interface{} {
220		cleaned := make(map[string]interface{})
221		removeSet := make(map[string]bool)
222		for _, f := range fieldsToRemove {
223			removeSet[f] = true
224		}
225		for k, v := range resource {
226			if !removeSet[k] {
227				cleaned[k] = v
228			}
229		}
230		return cleaned
231	}
