261	// blueprintRelatesToInheritedOwnership checks if a blueprint has ANY relation to a blueprint with inherited ownership.
262	// This is used to skip all entities from such blueprints, since Port will reject them.
263	func blueprintRelatesToInheritedOwnership(blueprintID string, inheritedOwnershipBPs map[string]bool, relationTargets map[string]map[string]string) bool {
264		// Get the relation targets for this blueprint
265		bpRelations, ok := relationTargets[blueprintID]
266		if !ok {
267			return false
268		}
269	
270		// Check if any relation targets an inherited ownership blueprint
271		for _, targetBP := range bpRelations {
272			if inheritedOwnershipBPs[targetBP] {
273				return true
274			}
275		}
276	
277		return false
278	}
