280	// detectInheritedOwnershipBlueprints fetches blueprints and returns:
281	// 1. A set of blueprint IDs that have inherited ownership enabled
282	// 2. A map of blueprintID -> relationName -> targetBlueprintID for all blueprints
283	func (i *Importer) detectInheritedOwnershipBlueprints(ctx context.Context) (map[string]bool, map[string]map[string]string) {
284		inheritedOwnership := make(map[string]bool)
285		relationTargets := make(map[string]map[string]string)
286	
287		blueprints, err := i.client.GetBlueprints(ctx)
288		if err != nil {
289			// If we can't fetch blueprints, return empty maps and let errors occur naturally
290			return inheritedOwnership, relationTargets
291		}
292	
293		for _, bp := range blueprints {
294			id, ok := bp["identifier"].(string)
295			if !ok || id == "" {
296				continue
297			}
298	
299			// Check for teamInheritance field with inheritOwnership property
300			if teamInheritance, ok := bp["teamInheritance"].(map[string]interface{}); ok {
301				if inheritOwnership, ok := teamInheritance["inheritOwnership"].(bool); ok && inheritOwnership {
302					inheritedOwnership[id] = true
303				}
304			}
305	
306			// Also check the older/alternative field name
307			if inheritOwnershipVal, ok := bp["inheritedOwnership"].(bool); ok && inheritOwnershipVal {
308				inheritedOwnership[id] = true
309			}
310	
311			// Extract relation targets for this blueprint
312			if relations, ok := bp["relations"].(map[string]interface{}); ok {
313				relationTargets[id] = make(map[string]string)
314				for relName, relDef := range relations {
315					if relMap, ok := relDef.(map[string]interface{}); ok {
316						if target, ok := relMap["target"].(string); ok {
317							relationTargets[id][relName] = target
318						}
319					}
320				}
321			}
322		}
323	
324		return inheritedOwnership, relationTargets
325	}
