361	// Import imports data to Port with proper dependency ordering.
362	func (i *Importer) Import(ctx context.Context, data *export.Data, opts Options) (*Result, error) {
363		// Set progress callback if provided
364		if opts.ProgressCallback != nil {
365			i.progress = opts.ProgressCallback
366		}
367		i.verbose = opts.Verbose
368		if opts.LogCallback != nil {
369			i.log = opts.LogCallback
370		}
371	
372		result := &Result{
373			Errors:           []string{},
374			ErrorsByCategory: make(map[string][]string),
375			Warnings:         []ValidationWarning{},
376		}
377	
378		// Import blueprints with three-phase approach
379		if shouldImport("blueprints", opts.IncludeResources) {
380			if err := i.importBlueprints(ctx, data.Blueprints, result); err != nil {
381				return nil, err
382			}
383		}
384	
385		// Import other resources concurrently (but with bounded concurrency)
386		if err := i.importOtherResources(ctx, data, opts, result); err != nil {
387			return nil, err
388		}
389	
390		// Convert collected errors to string slice for backward compatibility
391		result.Errors = i.errors.ToStringSlice()
392	
393		// Populate errors by category for verbose output
394		for _, category := range []ErrorCategory{
395			ErrDependency, ErrAuth, ErrBlueprintConfig, ErrValidation,
396			ErrSchemaMismatch, ErrRateLimit, ErrNetwork, ErrConflict,
397			ErrNotFound, ErrUnknown,
398		} {
399			categoryErrors := i.errors.GetByCategory(category)
400			if len(categoryErrors) > 0 {
401				categoryStrings := make([]string, len(categoryErrors))
402				for j, e := range categoryErrors {
403					categoryStrings[j] = e.Error()
404				}
405				result.ErrorsByCategory[string(category)] = categoryStrings
406			}
407		}
408	
409		return result, nil
410	}
