412	// importBlueprints imports blueprints using a multi-phase approach:
413	// Phase 1: Create non-system blueprints with relations and dependent fields stripped
414	// Phase 2a: Add relations back to all blueprints
415	// Phase 2b: Add calculationProperties (self-contained, no cross-blueprint dependencies)
416	// Phase 2c: Add mirrorProperties (depend on relations existing)
417	// Phase 2d: Add aggregationProperties (depend on properties existing on OTHER blueprints)
418	// Phase 3: Update system blueprints
419	func (i *Importer) importBlueprints(ctx context.Context, blueprints []api.Blueprint, result *Result) error {
420		// Separate system and non-system blueprints
421		nonSystemBPs, systemBPs := SeparateSystemBlueprints(blueprints)
422	
423		// Build existing blueprints set (system blueprints are assumed to exist)
424		existingBPs := make(map[string]bool)
425		for _, bp := range systemBPs {
426			if id, ok := bp["identifier"].(string); ok {
427				existingBPs[id] = true
428			}
429		}
430		// Also add common system blueprints that might not be in export
431		for _, id := range CommonSystemBlueprints() {
432			existingBPs[id] = true
433		}
434	
435		// Store each field type separately for ordered updates in Phase 2
436		storedRelations := make(map[string]map[string]interface{})
437		storedCalcProps := make(map[string]map[string]interface{})
438		storedMirrorProps := make(map[string]map[string]interface{})
439		storedAggProps := make(map[string]map[string]interface{})
440		storedOwnership := make(map[string]map[string]interface{})
441		strippedBPs := make([]api.Blueprint, 0, len(nonSystemBPs))
442	
443		for _, bp := range nonSystemBPs {
444			id, ok := bp["identifier"].(string)
445			if !ok || id == "" {
446				i.errors.Add(fmt.Errorf("blueprint is missing identifier field, skipping"), "blueprint", "<unknown>")
447				continue
448			}
449	
450			// Extract and store relations
451			if relations, ok := bp["relations"].(map[string]interface{}); ok && len(relations) > 0 {
452				storedRelations[id] = relations
453			}
454	
455			// Extract and store each dependent field type separately
456			if calcProps, ok := bp["calculationProperties"].(map[string]interface{}); ok && len(calcProps) > 0 {
457				storedCalcProps[id] = calcProps
458			}
459			if mirrorProps, ok := bp["mirrorProperties"].(map[string]interface{}); ok && len(mirrorProps) > 0 {
460				storedMirrorProps[id] = mirrorProps
461			}
462			if aggProps, ok := bp["aggregationProperties"].(map[string]interface{}); ok && len(aggProps) > 0 {
463				storedAggProps[id] = aggProps
464			}
465			if ownership, ok := bp["ownership"].(map[string]interface{}); ok && len(ownership) > 0 {
466				storedOwnership[id] = ownership
467			}
468	
469			// Strip both relations AND dependent fields for phase 1
470			stripped := StripDependentFields(bp)
471			stripped = StripRelations(stripped)
472			strippedBPs = append(strippedBPs, stripped)
473		}
474	
475		// Topological sort
476		levels, cyclic := TopologicalSort(strippedBPs, existingBPs)
477	
478		// Add warning about cyclic blueprints
479		if len(cyclic) > 0 {
480			cyclicIDs := make([]string, 0, len(cyclic))
481			for _, bp := range cyclic {
482				if id, ok := bp["identifier"].(string); ok {
483					cyclicIDs = append(cyclicIDs, id)
484				}
485			}
486			result.Warnings = append(result.Warnings, ValidationWarning{
487				Type:    "cycle",
488				Message: fmt.Sprintf("Detected %d blueprints with circular dependencies", len(cyclic)),
489				Details: cyclicIDs,
490			})
491		}
492	
493		// Track successfully created blueprints
494		successfulBPs := make(map[string]bool)
495		for id := range existingBPs {
496			successfulBPs[id] = true
497		}
498	
499		// Phase 1: Create non-system blueprints in dependency order
500		pool := NewWorkerPool(BlueprintConcurrency)
501		totalBPs := len(FlattenLevels(levels)) + len(cyclic)
502		createdCount := 0
503	
504		for levelIdx, level := range levels {
505			i.reportProgress(fmt.Sprintf("Blueprints (level %d/%d)", levelIdx+1, len(levels)), createdCount, totalBPs)
506	
507			var levelMu sync.Mutex
508			for _, bp := range level {
509				bp := bp
510				pool.Go(func() {
511					id := bp["identifier"].(string)
512					created, updated, err := i.createOrUpdateBlueprint(ctx, bp)
513	
514					i.mu.Lock()
515					if err != nil {
516						i.errors.Add(err, "blueprint", id)
517					} else {
518						if created {
519							result.BlueprintsCreated++
520						} else if updated {
521							result.BlueprintsUpdated++
522						}
523						levelMu.Lock()
524						successfulBPs[id] = true
525						levelMu.Unlock()
526					}
527					createdCount++
528					i.mu.Unlock()
529				})
530			}
531			pool.Wait()
532		}
533	
534		// Handle cyclic blueprints (best effort)
535		if len(cyclic) > 0 {
536			i.reportProgress("Blueprints (cyclic)", createdCount, totalBPs)
537			for _, bp := range cyclic {
538				bp := bp
539				pool.Go(func() {
540					id := bp["identifier"].(string)
541					created, updated, err := i.createOrUpdateBlueprint(ctx, bp)
542	
543					i.mu.Lock()
544					if err != nil {
545						i.errors.Add(err, "blueprint", id)
546					} else {
547						if created {
548							result.BlueprintsCreated++
549						} else if updated {
550							result.BlueprintsUpdated++
551						}
552						successfulBPs[id] = true
553					}
554					createdCount++
555					i.mu.Unlock()
556				})
557			}
558			pool.Wait()
559		}
560	
561		// Fetch ALL existing blueprints from target for validation
562		allExistingBPs := make(map[string]bool)
563		for id := range successfulBPs {
564			allExistingBPs[id] = true
565		}
566		targetBlueprints, err := i.client.GetBlueprints(ctx)
567		if err == nil {
568			for _, bp := range targetBlueprints {
569				if id, ok := bp["identifier"].(string); ok && id != "" {
570					allExistingBPs[id] = true
571				}
572			}
573		}
574	
575		// Phase 2a: Add relations back to all blueprints
576		if len(storedRelations) > 0 {
577			i.reportProgress("Blueprints (adding relations)", 0, len(storedRelations))
578			count := 0
579			for id, relations := range storedRelations {
580				if !allExistingBPs[id] {
581					continue
582				}
583				id, relations := id, relations
584				pool.Go(func() {
585					err := i.updateBlueprintFieldsDirect(ctx, id, map[string]interface{}{"relations": relations})
586					i.mu.Lock()
587					if err != nil {
588						i.errors.Add(err, "blueprint", id)
589					}
590					count++
591					i.reportProgress("Blueprints (adding relations)", count, len(storedRelations))
592					i.mu.Unlock()
593				})
594			}
595			pool.Wait()
596		}
597	
598		// Phase 2b: Add calculationProperties (self-contained, no cross-blueprint deps)
599		if len(storedCalcProps) > 0 {
600			i.reportProgress("Blueprints (adding calculationProperties)", 0, len(storedCalcProps))
601			count := 0
602			for id, calcProps := range storedCalcProps {
603				if !allExistingBPs[id] {
604					continue
605				}
606				id, calcProps := id, calcProps
607				pool.Go(func() {
608					err := i.updateBlueprintFieldsDirect(ctx, id, map[string]interface{}{"calculationProperties": calcProps})
609					i.mu.Lock()
610					if err != nil {
611						i.errors.Add(err, "blueprint", id)
612					}
613					count++
614					i.reportProgress("Blueprints (adding calculationProperties)", count, len(storedCalcProps))
615					i.mu.Unlock()
616				})
617			}
618			pool.Wait()
619		}
620	
621		// Phase 2c: Add mirrorProperties (depend on relations existing)
622		if len(storedMirrorProps) > 0 {
623			i.reportProgress("Blueprints (adding mirrorProperties)", 0, len(storedMirrorProps))
624			count := 0
625			for id, mirrorProps := range storedMirrorProps {
626				if !allExistingBPs[id] {
627					continue
628				}
629				id, mirrorProps := id, mirrorProps
630				pool.Go(func() {
631					err := i.updateBlueprintFieldsDirect(ctx, id, map[string]interface{}{"mirrorProperties": mirrorProps})
632					i.mu.Lock()
633					if err != nil {
634						i.errors.Add(err, "blueprint", id)
635					}
636					count++
637					i.reportProgress("Blueprints (adding mirrorProperties)", count, len(storedMirrorProps))
638					i.mu.Unlock()
639				})
640			}
641			pool.Wait()
642		}
643	
644		// Phase 2d: Add aggregationProperties (depend on properties on OTHER blueprints).
645		// Run twice: some aggregations reference aggregationProperties on other blueprints
646		// that are created in the same pass, so a second pass resolves those dependencies.
647		if len(storedAggProps) > 0 {
648			for pass := 1; pass <= 2; pass++ {
649				label := fmt.Sprintf("Blueprints (adding aggregationProperties, pass %d/2)", pass)
650				i.reportProgress(label, 0, len(storedAggProps))
651				count := 0
652				var failedIDs []string
653				var failedMu sync.Mutex
654				for id, aggProps := range storedAggProps {
655					if !allExistingBPs[id] {
656						continue
657					}
658					id, aggProps := id, aggProps
659					pool.Go(func() {
660						err := i.updateBlueprintFieldsDirect(ctx, id, map[string]interface{}{"aggregationProperties": aggProps})
661						i.mu.Lock()
662						count++
663						i.reportProgress(label, count, len(storedAggProps))
664						i.mu.Unlock()
665						if err != nil && pass == 1 {
666							failedMu.Lock()
667							failedIDs = append(failedIDs, id)
668							failedMu.Unlock()
669						} else if err != nil {
670							i.mu.Lock()
671							i.errors.Add(err, "blueprint", id)
672							i.mu.Unlock()
673						}
674					})
675				}
676				pool.Wait()
677	
678				// Second pass only retries blueprints that failed in the first pass.
679				if pass == 1 {
680					next := make(map[string]map[string]interface{}, len(failedIDs))
681					for _, id := range failedIDs {
682						next[id] = storedAggProps[id]
683					}
684					storedAggProps = next
685				}
686			}
687		}
688	
689		// Phase 2e: Add ownership (inherited ownership depends on relations existing)
690		if len(storedOwnership) > 0 {
691			var ownershipBlueprints []api.Blueprint
692			for _, bp := range append(nonSystemBPs, systemBPs...) {
693				id, ok := bp["identifier"].(string)
694				if !ok || id == "" {
695					continue
696				}
697				if ownership, ok := storedOwnership[id]; ok && len(ownership) > 0 {
698					ownershipBlueprints = append(ownershipBlueprints, bp)
699				}
700			}
701	
702			levels, cyclic := TopologicalSortOwnership(ownershipBlueprints)
703			totalOwnership := len(FlattenLevels(levels)) + len(cyclic)
704			appliedCount := 0
705	
706			for levelIdx, level := range levels {
707				i.reportProgress(fmt.Sprintf("Blueprints (adding ownership level %d/%d)", levelIdx+1, len(levels)), appliedCount, totalOwnership)
708				for _, bp := range level {
709					id := bp["identifier"].(string)
710					if !allExistingBPs[id] {
711						continue
712					}
713					ownership := storedOwnership[id]
714					pool.Go(func() {
715						err := i.updateBlueprintFieldsDirect(ctx, id, map[string]interface{}{"ownership": ownership})
716						i.mu.Lock()
717						if err != nil {
718							i.errors.Add(err, "blueprint", id)
719						}
720						appliedCount++
721						i.mu.Unlock()
722					})
723				}
724				pool.Wait()
725			}
726	
727			if len(cyclic) > 0 {
728				i.reportProgress("Blueprints (adding ownership cyclic)", appliedCount, totalOwnership)
729				for _, bp := range cyclic {
730					id := bp["identifier"].(string)
731					if !allExistingBPs[id] {
732						continue
733					}
734					ownership := storedOwnership[id]
735					pool.Go(func() {
736						err := i.updateBlueprintFieldsDirect(ctx, id, map[string]interface{}{"ownership": ownership})
737						i.mu.Lock()
738						if err != nil {
739							i.errors.Add(err, "blueprint", id)
740						}
741						appliedCount++
742						i.mu.Unlock()
743					})
744				}
745				pool.Wait()
746			}
747		}
748	
749		// Phase 3: Update system blueprints
750		if len(systemBPs) > 0 {
751			i.reportProgress("System blueprints", 0, len(systemBPs))
752			sysCount := 0
753	
754			for _, bp := range systemBPs {
755				bp := bp
756				pool.Go(func() {
757					id := bp["identifier"].(string)
758					_, updated, err := i.createOrUpdateBlueprint(ctx, bp)
759	
760					i.mu.Lock()
761					if err != nil {
762						i.errors.Add(err, "blueprint", id)
763					} else if updated {
764						result.BlueprintsUpdated++
765					}
766					sysCount++
767					i.reportProgress("System blueprints", sysCount, len(systemBPs))
768					i.mu.Unlock()
769				})
770			}
771			pool.Wait()
772		}
773	
774		return nil
775	}
