777	// createOrUpdateBlueprint creates or updates a single blueprint.
778	// Returns (created, updated, error).
779	func (i *Importer) createOrUpdateBlueprint(ctx context.Context, bp api.Blueprint) (bool, bool, error) {
780		id, _ := bp["identifier"].(string)
781	
782		// Try create first
783		_, err := i.client.CreateBlueprint(ctx, bp)
784		if err == nil {
785			return true, false, nil
786		}
787	
788		// If conflict, try update
789		if isConflictError(err) {
790			_, updateErr := i.client.UpdateBlueprint(ctx, id, bp)
791			if updateErr != nil {
792				return false, false, updateErr
793			}
794			return false, true, nil
795		}
796	
797		return false, false, err
798	}
