800	// updateBlueprintFields updates a blueprint with dependent fields (relations, mirrorProperties, etc.).
801	// Deprecated: Use updateBlueprintFieldsDirect instead for phased updates.
802	func (i *Importer) updateBlueprintFields(ctx context.Context, id string, fields map[string]interface{}, existingBPs map[string]bool) error {
803		// Validate dependencies before update
804		tempBP := api.Blueprint(fields)
805		missing := ValidateAllDependencies(tempBP, existingBPs)
806		if len(missing) > 0 {
807			return fmt.Errorf("cannot add dependent fields - missing blueprints: %v", missing)
808		}
809	
810		// Fetch existing blueprint
811		existing, err := i.client.GetBlueprint(ctx, id)
812		if err != nil {
813			return fmt.Errorf("failed to fetch blueprint: %w", err)
814		}
815	
816		// Merge in the dependent fields
817		for k, v := range fields {
818			existing[k] = v
819		}
820	
821		// Update
822		_, err = i.client.UpdateBlueprint(ctx, id, existing)
823		if err != nil {
824			return fmt.Errorf("failed to update with dependent fields: %w", err)
825		}
826	
827		return nil
828	}
