830	// updateBlueprintFieldsDirect updates a blueprint by merging in specific fields.
831	// This fetches the existing blueprint and merges the new fields, properly handling
832	// nested maps (like adding new properties to existing calculationProperties).
833	func (i *Importer) updateBlueprintFieldsDirect(ctx context.Context, id string, fields map[string]interface{}) error {
834		// Fetch existing blueprint
835		existing, err := i.client.GetBlueprint(ctx, id)
836		if err != nil {
837			return fmt.Errorf("failed to fetch blueprint: %w", err)
838		}
839	
840		// Merge in the new fields
841		// For nested maps (relations, calculationProperties, etc.), merge the contents
842		for k, v := range fields {
843			if newMap, ok := v.(map[string]interface{}); ok {
844				// Check if existing has this field as a map
845				if existingMap, ok := existing[k].(map[string]interface{}); ok {
846					// Merge: add new items to existing map
847					for itemKey, itemVal := range newMap {
848						existingMap[itemKey] = itemVal
849					}
850					existing[k] = existingMap
851				} else {
852					// No existing value or not a map, just set it
853					existing[k] = v
854				}
855			} else {
856				existing[k] = v
857			}
858		}
859	
860		// Update
861		_, err = i.client.UpdateBlueprint(ctx, id, existing)
862		if err != nil {
863			return fmt.Errorf("failed to update blueprint fields: %w", err)
864		}
865	
866		return nil
867	}
