869	// importOtherResources imports non-blueprint resources with bounded concurrency.
870	func (i *Importer) importOtherResources(ctx context.Context, data *export.Data, opts Options, result *Result) error {
871		// Import entities
872		if !opts.SkipEntities && shouldImport("entities", opts.IncludeResources) {
873			if err := i.importEntities(ctx, data.Entities, result); err != nil {
874				return err
875			}
876		}
877	
878		// Import other resources concurrently with bounded concurrency
879		pool := NewWorkerPool(DefaultConcurrency)
880	
881		// Import scorecards
882		if shouldImport("scorecards", opts.IncludeResources) {
883			i.importScorecards(ctx, data.Scorecards, result, pool)
884		}
885	
886		// Import actions
887		if shouldImport("actions", opts.IncludeResources) || shouldImport("automations", opts.IncludeResources) {
888			i.importActions(ctx, data.Actions, result, pool)
889		}
890	
891		// Import teams
892		if !opts.SkipEntities && shouldImport("teams", opts.IncludeResources) {
893			i.importTeams(ctx, data.Teams, result, pool)
894		}
895	
896		// Import users
897		if !opts.SkipEntities && shouldImport("users", opts.IncludeResources) {
898			i.importUsers(ctx, data.Users, result, pool)
899		}
900	
901		// Import integrations
902		if shouldImport("integrations", opts.IncludeResources) {
903			i.importIntegrations(ctx, data.Integrations, result, pool)
904		}
905	
906		pool.Wait()
907	
908		// Import pages level-by-level in topological `after` order.
909		// Sidebar resources are executed through a shared pipeline so folders and pages
910		// can depend on each other via `parent` and `after`.
911		if shouldImport("pages", opts.IncludeResources) {
912			i.importSidebarPipeline(ctx, PlanSidebarPipeline(data.Folders, data.Pages), result)
913		}
914	
915		return nil
916	}
