944	// importEntities imports entities with two-phase approach and bounded concurrency.
945	// Phase 1: Create all entities with relations stripped (to avoid missing entity references)
946	// Phase 2: Update entities that have relations to add them back
947	func (i *Importer) importEntities(ctx context.Context, entities []api.Entity, result *Result) error {
948		if len(entities) == 0 {
949			return nil
950		}
951	
952		// Fetch blueprints to detect those with inherited ownership and build relation target map
953		inheritedOwnershipBPs, relationTargets := i.detectInheritedOwnershipBlueprints(ctx)
954	
955		// Build set of blueprints that relate to inherited ownership blueprints
956		blueprintsToSkip := make(map[string]bool)
957		for bpID := range relationTargets {
958			if blueprintRelatesToInheritedOwnership(bpID, inheritedOwnershipBPs, relationTargets) {
959				blueprintsToSkip[bpID] = true
960			}
961		}
962	
963		// Filter out entities that:
964		// 1. Belong to protected system blueprints
965		// 2. Belong to blueprints with inherited ownership
966		// 3. Belong to blueprints that have relations to inherited ownership blueprints
967		filteredEntities := make([]api.Entity, 0, len(entities))
968		protectedSkipped := 0
969		inheritedOwnershipSkipped := 0
970		for _, entity := range entities {
971			blueprintID, _ := entity["blueprint"].(string)
972			if isProtectedBlueprint(blueprintID) {
973				protectedSkipped++
974				continue
975			}
976			if inheritedOwnershipBPs[blueprintID] {
977				inheritedOwnershipSkipped++
978				continue
979			}
980			// Check if blueprint has relations to inherited ownership blueprints
981			if blueprintsToSkip[blueprintID] {
982				inheritedOwnershipSkipped++
983				continue
984			}
985			filteredEntities = append(filteredEntities, entity)
986		}
987	
988		skippedMsg := ""
989		if protectedSkipped > 0 || inheritedOwnershipSkipped > 0 {
990			parts := []string{}
991			if protectedSkipped > 0 {
992				parts = append(parts, fmt.Sprintf("%d protected", protectedSkipped))
993			}
994			if inheritedOwnershipSkipped > 0 {
995				parts = append(parts, fmt.Sprintf("%d inherited-ownership", inheritedOwnershipSkipped))
996			}
997			skippedMsg = fmt.Sprintf(" (skipped %s)", strings.Join(parts, ", "))
998		}
999	
1000		total := len(filteredEntities)
1001	
1002		// Separate entities with and without relations
1003		entitiesWithRelations := make([]api.Entity, 0)
1004		for _, entity := range filteredEntities {
1005			if HasEntityRelations(entity) {
1006				entitiesWithRelations = append(entitiesWithRelations, entity)
1007			}
1008		}
1009	
1010		// Phase 1: Create/update all entities with relations stripped
1011		i.reportProgress(fmt.Sprintf("Entities Phase 1%s", skippedMsg), 0, total)
1012		pool := NewWorkerPool(EntityConcurrency)
1013		processedCount := 0
1014		successfulEntities := make(map[string]bool)
1015		var successMu sync.Mutex
1016	
1017		for _, entity := range filteredEntities {
1018			entity := entity
1019			pool.Go(func() {
1020				blueprintID, ok1 := entity["blueprint"].(string)
1021				entityID, ok2 := entity["identifier"].(string)
1022				if !ok1 || !ok2 || blueprintID == "" || entityID == "" {
1023					return
1024				}
1025	
1026				// Strip relations for phase 1
1027				strippedEntity := StripEntityRelations(entity)
1028				created, updated, err := i.createOrUpdateEntity(ctx, blueprintID, entityID, strippedEntity)
1029	
1030				i.mu.Lock()
1031				if err != nil {
1032					i.errors.Add(err, "entity", entityID)
1033				} else {
1034					if created {
1035						result.EntitiesCreated++
1036					} else if updated {
1037						result.EntitiesUpdated++
1038					}
1039					successMu.Lock()
1040					successfulEntities[fmt.Sprintf("%s:%s", blueprintID, entityID)] = true
1041					successMu.Unlock()
1042				}
1043				processedCount++
1044				if processedCount%100 == 0 || processedCount == total {
1045					i.reportProgress("Entities Phase 1", processedCount, total)
1046				}
1047				i.mu.Unlock()
1048			})
1049		}
1050	
1051		pool.Wait()
1052	
1053		// Phase 2: Update entities that have relations
1054		if len(entitiesWithRelations) > 0 {
1055			i.reportProgress("Entities Phase 2 (relations)", 0, len(entitiesWithRelations))
1056			pool2 := NewWorkerPool(EntityConcurrency)
1057			phase2Count := 0
1058	
1059			for _, entity := range entitiesWithRelations {
1060				entity := entity
1061				pool2.Go(func() {
1062					blueprintID, _ := entity["blueprint"].(string)
1063					entityID, _ := entity["identifier"].(string)
1064					key := fmt.Sprintf("%s:%s", blueprintID, entityID)
1065	
1066					// Only update if phase 1 succeeded
1067					successMu.Lock()
1068					wasSuccessful := successfulEntities[key]
1069					successMu.Unlock()
1070	
1071					if !wasSuccessful {
1072						return
1073					}
1074	
1075					// Update with full entity (including relations)
1076					_, updateErr := i.client.UpdateEntity(ctx, blueprintID, entityID, entity)
1077	
1078					i.mu.Lock()
1079					if updateErr != nil {
1080						i.errors.Add(updateErr, "entity", entityID)
1081					}
1082					phase2Count++
1083					if phase2Count%100 == 0 || phase2Count == len(entitiesWithRelations) {
1084						i.reportProgress("Entities Phase 2 (relations)", phase2Count, len(entitiesWithRelations))
1085					}
1086					i.mu.Unlock()
1087				})
1088			}
1089	
1090			pool2.Wait()
1091		}
1092	
1093		return nil
1094	}
