1096	// createOrUpdateEntity creates or updates a single entity.
1097	func (i *Importer) createOrUpdateEntity(ctx context.Context, blueprintID, entityID string, entity api.Entity) (bool, bool, error) {
1098		_, err := i.client.CreateEntity(ctx, blueprintID, entity)
1099		if err == nil {
1100			return true, false, nil
1101		}
1102	
1103		if isConflictError(err) {
1104			_, updateErr := i.client.UpdateEntity(ctx, blueprintID, entityID, entity)
1105			if updateErr != nil {
1106				return false, false, updateErr
1107			}
1108			return false, true, nil
1109		}
1110	
1111		return false, false, err
1112	}
