1120			scID, ok2 := sc["identifier"].(string)
1121			if !ok1 || !ok2 || bpID == "" || scID == "" {
1122				i.errors.Add(fmt.Errorf("scorecard is missing identifier or blueprintIdentifier field, skipping"), "scorecard", "<unknown>")
1123				continue
1124			}
1125			cleaned := cleanSystemFields(sc, []string{"createdBy", "updatedBy", "createdAt", "updatedAt", "id", "blueprint", "blueprintIdentifier"})
1126			byBlueprint[bpID] = append(byBlueprint[bpID], api.Scorecard(cleaned))
1127		}
1128	
1129		for bpID, scs := range byBlueprint {
1130			bpID := bpID
1131			scs := scs
1132			pool.Go(func() {
1133				for _, sc := range scs {
1134					scID := sc["identifier"].(string)
1135					_, err := i.client.CreateScorecard(ctx, bpID, sc)
1136	
1137					i.mu.Lock()
1138					if err == nil {
1139						result.ScorecardsCreated++
1140					} else if isConflictError(err) {
1141						// Try update via bulk endpoint
1142						_, updateErr := i.client.UpdateScorecards(ctx, bpID, []api.Scorecard{sc})
1143						if updateErr != nil {
1144							i.errors.Add(updateErr, "scorecard", scID)
1145						} else {
1146							result.ScorecardsUpdated++
1147						}
1148					} else {
1149						i.errors.Add(err, "scorecard", scID)
1150					}
1151					i.mu.Unlock()
1152				}
1153			})
1154		}
1155	}
