1378	func PlanSidebarPipeline(folders []api.Folder, pages []api.Page) []SidebarPipelineStep {
1379		opsByID := make(map[string]SidebarPipelineOperation, len(folders)+len(pages))
1380		inDegree := make(map[string]int, len(folders)+len(pages))
1381		dependents := make(map[string][]string, len(folders)+len(pages))
1382	
1383		for _, folder := range folders {
1384			id, _ := folder["identifier"].(string)
1385			if id == "" {
1386				continue
1387			}
1388			opsByID[id] = SidebarPipelineOperation{
1389				ResourceType: "folder",
1390				Identifier:   id,
1391				Folder:       folder,
1392			}
1393			inDegree[id] = 0
1394		}
1395		for _, page := range pages {
1396			id, _ := page["identifier"].(string)
1397			if id == "" {
1398				continue
1399			}
1400			opsByID[id] = SidebarPipelineOperation{
1401				ResourceType: "page",
1402				Identifier:   id,
1403				Page:         page,
1404			}
1405			inDegree[id] = 0
1406		}
1407	
1408		addDependency := func(id, dep string) {
1409			if id == "" || dep == "" || id == dep {
1410				return
1411			}
1412			if _, exists := opsByID[dep]; !exists {
1413				return
1414			}
1415			inDegree[id]++
1416			dependents[dep] = append(dependents[dep], id)
1417		}
1418	
1419		for _, folder := range folders {
1420			id, _ := folder["identifier"].(string)
1421			if id == "" {
1422				continue
1423			}
1424			deps := make(map[string]bool)
1425			if parent, _ := folder["parent"].(string); parent != "" {
1426				deps[parent] = true
1427			}
1428			if after, _ := folder["after"].(string); after != "" {
1429				deps[after] = true
1430			}
1431			for dep := range deps {
1432				addDependency(id, dep)
1433			}
1434		}
1435		for _, page := range pages {
1436			id, _ := page["identifier"].(string)
1437			if id == "" {
1438				continue
1439			}
1440			deps := make(map[string]bool)
1441			if parent, _ := page["parent"].(string); parent != "" {
1442				deps[parent] = true
1443			}
1444			if after, _ := page["after"].(string); after != "" {
1445				deps[after] = true
1446			}
1447			for dep := range deps {
1448				addDependency(id, dep)
1449			}
1450		}
1451	
1452		remaining := make(map[string]bool, len(opsByID))
1453		for id := range opsByID {
1454			remaining[id] = true
1455		}
1456	
1457		var steps []SidebarPipelineStep
1458		for len(remaining) > 0 {
1459			readyIDs := make([]string, 0, len(remaining))
1460			for id := range remaining {
1461				if inDegree[id] == 0 {
1462					readyIDs = append(readyIDs, id)
1463				}
1464			}
1465			if len(readyIDs) == 0 {
1466				for id := range remaining {
1467					readyIDs = append(readyIDs, id)
1468				}
1469			}
1470			sort.Strings(readyIDs)
1471	
1472			step := SidebarPipelineStep{
1473				Operations: make([]SidebarPipelineOperation, 0, len(readyIDs)),
1474			}
1475			for _, id := range readyIDs {
1476				step.Operations = append(step.Operations, opsByID[id])
1477			}
1478			steps = append(steps, step)
1479	
1480			for _, id := range readyIDs {
1481				delete(remaining, id)
1482				for _, dep := range dependents[id] {
1483					inDegree[dep]--
1484				}
1485			}
1486		}
1487	
1488		return steps
1489	}
