1491	func DescribeSidebarPipeline(steps []SidebarPipelineStep) []string {
1492		lines := make([]string, 0, len(steps))
1493		for idx, step := range steps {
1494			var folders []string
1495			var pages []string
1496			for _, op := range step.Operations {
1497				switch op.ResourceType {
1498				case "folder":
1499					folders = append(folders, op.Identifier)
1500				case "page":
1501					pages = append(pages, op.Identifier)
1502				}
1503			}
1504			sort.Strings(folders)
1505			sort.Strings(pages)
1506	
1507			parts := make([]string, 0, 2)
1508			if len(folders) > 0 {
1509				parts = append(parts, fmt.Sprintf("folders [%s]", strings.Join(folders, ", ")))
1510			}
1511			if len(pages) > 0 {
1512				parts = append(parts, fmt.Sprintf("pages [%s]", strings.Join(pages, ", ")))
1513			}
1514			lines = append(lines, fmt.Sprintf("Step %d: %s", idx+1, strings.Join(parts, " | ")))
1515		}
1516		return lines
1517	}
