1519	// sortPagesByAfterDeps returns pages sorted so that if page B has after=A and A is
1520	// also in the list, A comes before B.
1521	func sortPagesByAfterDeps(pages []api.Page) []api.Page {
1522		pageSet := make(map[string]bool, len(pages))
1523		for _, p := range pages {
1524			if id, ok := p["identifier"].(string); ok {
1525				pageSet[id] = true
1526			}
1527		}
1528	
1529		result := make([]api.Page, 0, len(pages))
1530		placed := make(map[string]bool, len(pages))
1531		remaining := make([]api.Page, len(pages))
1532		copy(remaining, pages)
1533	
1534		for len(remaining) > 0 {
1535			added := 0
1536			var next []api.Page
1537			for _, p := range remaining {
1538				after, _ := p["after"].(string)
1539				if !pageSet[after] || placed[after] {
1540					result = append(result, p)
1541					if id, ok := p["identifier"].(string); ok {
1542						placed[id] = true
1543					}
1544					added++
1545				} else {
1546					next = append(next, p)
1547				}
1548			}
1549			remaining = next
1550			if added == 0 {
1551				result = append(result, remaining...)
1552				break
1553			}
1554		}
1555		return result
1556	}
