1568	// sortPagesByAfterLevels groups pages into levels where all pages within a level
1569	// have no after-dependencies on each other. Pages in the same level can be
1570	// processed concurrently; levels must be processed sequentially.
1571	func sortPagesByAfterLevels(pages []api.Page) [][]api.Page {
1572		pageSet := make(map[string]bool, len(pages))
1573		pageByID := make(map[string]api.Page, len(pages))
1574		for _, p := range pages {
1575			if id, ok := p["identifier"].(string); ok && id != "" {
1576				pageSet[id] = true
1577				pageByID[id] = p
1578			}
1579		}
1580	
1581		inDegree := make(map[string]int, len(pages))
1582		dependents := make(map[string][]string, len(pages))
1583		for _, p := range pages {
1584			id, _ := p["identifier"].(string)
1585			if id == "" {
1586				continue
1587			}
1588			inDegree[id] = 0
1589		}
1590		for _, p := range pages {
1591			id, _ := p["identifier"].(string)
1592			after, _ := p["after"].(string)
1593			if id == "" || after == "" || !pageSet[after] {
1594				continue
1595			}
1596			inDegree[id]++
1597			dependents[after] = append(dependents[after], id)
1598		}
1599	
1600		remaining := make(map[string]bool, len(pages))
1601		for id := range inDegree {
1602			remaining[id] = true
1603		}
1604	
1605		var levels [][]api.Page
1606		for len(remaining) > 0 {
1607			var level []api.Page
1608			for id := range remaining {
1609				if inDegree[id] == 0 {
1610					level = append(level, pageByID[id])
1611				}
1612			}
1613			if len(level) == 0 {
1614				// Cycle — flush all remaining to break deadlock.
1615				for id := range remaining {
1616					level = append(level, pageByID[id])
1617				}
1618			}
1619			for _, p := range level {
1620				id, _ := p["identifier"].(string)
1621				delete(remaining, id)
1622				for _, dep := range dependents[id] {
1623					inDegree[dep]--
1624				}
1625			}
1626			levels = append(levels, level)
1627		}
1628		return levels
1629	}
