1631	// applyPageOrdering applies the `after` field for pages that have one, sequentially
1632	// and in topological dependency order. This is called after the concurrent page
1633	// content pass so that sidebar ordering is set without race conditions.
1634	func (i *Importer) applyPageOrdering(ctx context.Context, pages []api.Page, result *Result) {
1635		// Collect pages that have a non-empty after value.
1636		var toOrder []api.Page
1637		for _, p := range pages {
1638			if after, ok := p["after"].(string); ok && after != "" {
1639				toOrder = append(toOrder, p)
1640			}
1641		}
1642		if len(toOrder) == 0 {
1643			return
1644		}
1645	
1646		sorted := sortPagesByAfterDeps(toOrder)
1647		for _, p := range sorted {
1648			pageID, ok := p["identifier"].(string)
1649			if !ok || pageID == "" {
1650				continue
1651			}
1652			after := p["after"].(string)
1653			_, err := i.client.UpdatePage(ctx, pageID, api.Page{"identifier": pageID, "after": after})
1654			if err != nil {
1655				// A missing sibling is benign — the page exists, just not in the exact spot.
1656				if !isSidebarParentNotFound(err) {
1657					i.errors.Add(err, "page", pageID)
1658				}
1659			}
1660		}
1661	}
1662	
1663	// importPages imports pages in topological `after` order.
1664	// Pages are grouped into levels: all pages in a level are independent of each
1665	// other (no after-dependency between them) and can run concurrently. Levels are
1666	// processed sequentially so that `after` targets are always present before their
1667	// dependents. This avoids race conditions without a separate second pass.
1668	func (i *Importer) importPages(ctx context.Context, pages []api.Page, result *Result) {
1669		levels := sortPagesByAfterLevels(pages)
1670		for _, level := range levels {
1671			pool := NewWorkerPool(DefaultConcurrency)
1672			for _, page := range level {
1673				page := page
1674				pool.Go(func() {
1675					i.importPage(ctx, page, result)
1676				})
1677			}
1678			pool.Wait()
1679		}
1680	}
1681	
1682	// importPage imports a single page.
1683	func (i *Importer) importPage(ctx context.Context, page api.Page, result *Result) {
1684		pageID, ok := page["identifier"].(string)
1685		if !ok || pageID == "" {
1686			return
1687		}
1688	
1689		// metaFields are always stripped (audit metadata, internal IDs).
1690		metaFields := []string{"createdBy", "updatedBy", "createdAt", "updatedAt", "id", "protected"}
1691		// navFields control sidebar placement.
1692		navFields := []string{"after", "section", "sidebar", "parent", "requiredQueryParams"}
1693	
1694		// buildPage strips the given extra fields and recursively cleans widget metadata.
1695		buildPage := func(extra []string) api.Page {
1696			strip := append(metaFields, extra...)
1697			cleaned := cleanSystemFields(page, strip)
1698			if widgets, ok := cleaned["widgets"].([]interface{}); ok {
1699				cleaned["widgets"] = cleanWidgetsRecursive(widgets)
1700			}
1701			return api.Page(cleaned)
1702		}
1703	
1704		// pageForCreate keeps `type` and sidebar placement fields, but strips
1705		// requiredQueryParams because Port rejects it for some page types on create.
1706		pageForCreate := buildPage([]string{"requiredQueryParams"})
1707		// pageForUpdate keeps navigation fields (including `after`) so Port places the
1708		// page in the correct sidebar position. `type` is stripped because the PATCH
1709		// endpoint rejects it. Null string nav fields are stripped to avoid clearing
1710		// existing values in the target.
1711		pageForUpdate := buildPage([]string{"type", "requiredQueryParams", "sidebar"})
1712		for _, field := range navFields {
1713			if v, exists := pageForUpdate[field]; exists && v == nil {
1714				delete(pageForUpdate, field)
1715			}
1716		}
1717		var (
1718			createPosted api.Page
1719			createdPage  api.Page
1720			err          error
1721		)
1722	
1723		createPosted = pageForCreate
1724		createdPage, err = i.client.CreatePage(ctx, createPosted)
1725	
1726		needsUpdate := false
1727		i.mu.Lock()
1728		if err == nil {
1729			result.PagesCreated++
1730			i.mu.Unlock()
1731			i.logPageCreateMismatch(ctx, pageID, pageForCreate, createPosted, createdPage)
1732			return
1733		} else if IsAfterItemNotInParent(err) || extractAdditionalProperty(err) != "" {
1734			createPosted, createdPage, retryErr := i.retryCreatePageWithNarrowFallbacks(ctx, pageForCreate, err)
1735			if retryErr == nil {
1736				result.PagesCreated++
1737				i.mu.Unlock()
1738				i.logPageCreateMismatch(ctx, pageID, pageForCreate, createPosted, createdPage)
1739				return
1740			} else if isConflictError(retryErr) {
1741				needsUpdate = true
1742			}
1743		} else if isConflictError(err) {
1744			needsUpdate = true
1745		} else if strings.Contains(err.Error(), "agentIdentifier") {
1746			// Create failed with agentIdentifier — check if the page already exists.
1747			existingPage, fetchErr := i.client.GetPage(ctx, pageID)
1748			if fetchErr == nil && existingPage != nil {
1749				pageWithoutWidgets := make(api.Page)
1750				for k, v := range pageForUpdate {
1751					if k != "widgets" {
1752						pageWithoutWidgets[k] = v
1753					}
1754				}
1755				_, updateErr := i.client.UpdatePage(ctx, pageID, pageWithoutWidgets)
1756				if updateErr != nil {
1757					i.errors.Add(updateErr, "page", pageID)
1758				} else {
1759					result.PagesUpdated++
1760				}
1761			} else {
1762				i.errors.Add(err, "page", pageID)
1763			}
1764		} else {
1765			i.errors.Add(err, "page", pageID)
1766		}
1767	
1768		if needsUpdate {
1769			// Fetch existing page to preserve fields like agentIdentifier.
1770			existingPage, fetchErr := i.client.GetPage(ctx, pageID)
1771			if fetchErr == nil && existingPage != nil {
1772				if existingWidgets, ok := existingPage["widgets"].([]interface{}); ok {
1773					if newWidgets, ok := pageForUpdate["widgets"].([]interface{}); ok {
1774						pageForUpdate["widgets"] = mergeWidgetAgentIdentifiers(newWidgets, existingWidgets)
1775					}
1776				}
1777			}
1778	
1779			_, updateErr := i.client.UpdatePage(ctx, pageID, pageForUpdate)
1780			if updateErr != nil {
1781				if IsAfterItemNotInParent(updateErr) || extractAdditionalProperty(updateErr) != "" {
1782					_, retryErr := i.retryUpdatePageWithNarrowFallbacks(ctx, pageID, pageForUpdate, updateErr)
1783					if retryErr != nil {
1784						i.errors.Add(retryErr, "page", pageID)
1785					} else {
1786						result.PagesUpdated++
1787					}
1788				} else if strings.Contains(updateErr.Error(), "agentIdentifier") {
1789					// Fetch existing page to merge agentIdentifiers from its widgets, then retry.
1790					if existingPage, fetchErr := i.client.GetPage(ctx, pageID); fetchErr == nil && existingPage != nil {
1791						if existingWidgets, ok := existingPage["widgets"].([]interface{}); ok {
1792							if newWidgets, ok := pageForUpdate["widgets"].([]interface{}); ok {
1793								pageForUpdate["widgets"] = mergeWidgetAgentIdentifiers(newWidgets, existingWidgets)
1794							}
1795						}
1796					}
1797					_, retryErr := i.client.UpdatePage(ctx, pageID, pageForUpdate)
1798					if retryErr != nil {
1799						// Last resort: update without widgets.
1800						pageWithoutWidgets := make(api.Page)
1801						for k, v := range pageForUpdate {
1802							if k != "widgets" {
1803								pageWithoutWidgets[k] = v
1804							}
1805						}
1806						_, lastErr := i.client.UpdatePage(ctx, pageID, pageWithoutWidgets)
1807						if lastErr != nil {
1808							i.errors.Add(lastErr, "page", pageID)
1809						} else {
1810							result.PagesUpdated++
1811						}
1812					} else {
1813						result.PagesUpdated++
1814					}
1815				} else {
1816					i.errors.Add(updateErr, "page", pageID)
1817				}
1818			} else {
1819				result.PagesUpdated++
1820			}
1821		}
1822		i.mu.Unlock()
1823	}
