1825	func (i *Importer) logPageCreateMismatch(ctx context.Context, pageID string, intended api.Page, posted api.Page, created api.Page) {
1826		if !i.verbose {
1827			return
1828		}
1829		actualPage, err := i.client.GetPage(ctx, pageID)
1830		if err == nil && actualPage != nil {
1831			created = actualPage
1832		}
1833	
1834		normalizedIntended := normalizePageForLog(intended)
1835		normalizedPosted := normalizePageForLog(posted)
1836		normalizedCreated := normalizePageForLog(created)
1837	
1838		if subsetEqual(normalizedPosted, normalizedCreated) && subsetEqual(normalizedIntended, normalizedCreated) {
1839			return
1840		}
1841	
1842		lines := []string{
1843			fmt.Sprintf("Page create mismatch for %s", pageID),
1844		}
1845		if !subsetEqual(normalizedIntended, normalizedPosted) {
1846			lines = append(lines, fmt.Sprintf("  intended: %s", mustJSON(normalizedIntended)))
1847		}
1848		lines = append(lines,
1849			fmt.Sprintf("  posted: %s", mustJSON(normalizedPosted)),
1850			fmt.Sprintf("  created: %s", mustJSON(normalizedCreated)),
1851		)
1852		i.logLines(lines)
1853	}
