1935	func (i *Importer) retryCreatePageWithNarrowFallbacks(ctx context.Context, base api.Page, initialErr error) (api.Page, api.Page, error) {
1936		candidate := clonePage(base)
1937		currentErr := initialErr
1938	
1939		for {
1940			nextCandidate, changed := removeSingleFailingPageField(candidate, currentErr)
1941			if !changed {
1942				return candidate, nil, currentErr
1943			}
1944	
1945			createdPage, retryErr := i.client.CreatePage(ctx, nextCandidate)
1946			if retryErr == nil {
1947				return nextCandidate, createdPage, nil
1948			}
1949			if isConflictError(retryErr) {
1950				return nextCandidate, nil, retryErr
1951			}
1952	
1953			candidate = nextCandidate
1954			currentErr = retryErr
1955		}
1956	}
