1958	func (i *Importer) retryUpdatePageWithNarrowFallbacks(ctx context.Context, pageID string, base api.Page, initialErr error) (api.Page, error) {
1959		candidate := clonePage(base)
1960		currentErr := initialErr
1961	
1962		for {
1963			nextCandidate, changed := removeSingleFailingPageField(candidate, currentErr)
1964			if !changed {
1965				return candidate, currentErr
1966			}
1967	
1968			updatedPage, retryErr := i.client.UpdatePage(ctx, pageID, nextCandidate)
1969			if retryErr == nil {
1970				return updatedPage, nil
1971			}
1972	
1973			candidate = nextCandidate
1974			currentErr = retryErr
1975		}
1976	}
