1978	func removeSingleFailingPageField(page api.Page, err error) (api.Page, bool) {
1979		candidate := clonePage(page)
1980	
1981		if IsAfterItemNotInParent(err) {
1982			if _, exists := candidate["after"]; exists {
1983				delete(candidate, "after")
1984				return candidate, true
1985			}
1986		}
1987	
1988		if invalidProperty := extractAdditionalProperty(err); invalidProperty != "" {
1989			if _, exists := candidate[invalidProperty]; exists {
1990				delete(candidate, invalidProperty)
1991				return candidate, true
1992			}
1993		}
1994	
1995		return page, false
1996	}
