2012	func subsetEqual(expected, actual interface{}) bool {
2013		switch actualTyped := actual.(type) {
2014		case api.Page:
2015			return subsetEqual(expected, map[string]interface{}(actualTyped))
2016		case api.Folder:
2017			return subsetEqual(expected, map[string]interface{}(actualTyped))
2018		}
2019	
2020		switch expectedTyped := expected.(type) {
2021		case map[string]interface{}:
2022			actualTyped, ok := actual.(map[string]interface{})
2023			if !ok {
2024				return false
2025			}
2026			for key, expectedValue := range expectedTyped {
2027				actualValue, exists := actualTyped[key]
2028				if !exists || !subsetEqual(expectedValue, actualValue) {
2029					return false
2030				}
2031			}
2032			return true
2033		case api.Page:
2034			return subsetEqual(map[string]interface{}(expectedTyped), actual)
2035		case api.Folder:
2036			return subsetEqual(map[string]interface{}(expectedTyped), actual)
2037		case []interface{}:
2038			actualTyped, ok := actual.([]interface{})
2039			if !ok || len(expectedTyped) != len(actualTyped) {
2040				return false
2041			}
2042			for idx := range expectedTyped {
2043				if !subsetEqual(expectedTyped[idx], actualTyped[idx]) {
2044					return false
2045				}
2046			}
2047			return true
2048		default:
2049			return reflect.DeepEqual(expected, actual)
2050		}
2051	}
