2061	// pageMetaFields are the audit/internal fields always stripped before sending a page to Port.
2062	var pageMetaFields = []string{"createdBy", "updatedBy", "createdAt", "updatedAt", "id", "protected"}
2063	
2064	// pageNavFields control sidebar placement; Port rejects them when the referenced parent
2065	// doesn't exist in the target org.
2066	var pageNavFields = []string{"after", "section", "sidebar", "parent", "requiredQueryParams"}
2067	
2068	// CleanPageForCreate returns a copy of page with audit/internal fields removed.
2069	// Sidebar placement fields are preserved, but requiredQueryParams is stripped
2070	// because Port rejects it for some page types on create.
2071	func CleanPageForCreate(page api.Page) api.Page {
2072		strip := append(pageMetaFields, "requiredQueryParams")
