2111	// cleanWidgetsRecursive removes system fields from widgets and their nested widgets.
2112	// It also fixes widget configurations that would cause validation errors.
2113	func cleanWidgetsRecursive(widgets []interface{}) []interface{} {
2114		systemFields := map[string]bool{
2115			"createdBy": true, "updatedBy": true, "createdAt": true, "updatedAt": true,
2116		}
2117	
2118		result := make([]interface{}, 0, len(widgets))
2119		for _, w := range widgets {
2120			widget, ok := w.(map[string]interface{})
2121			if !ok {
2122				result = append(result, w)
2123				continue
2124			}
2125	
2126			// Clean system fields from this widget
2127			cleaned := make(map[string]interface{})
2128			for k, v := range widget {
2129				if systemFields[k] {
2130					continue
2131				}
2132				// Recursively clean nested widgets
2133				if k == "widgets" {
2134					if nestedWidgets, ok := v.([]interface{}); ok {
2135						cleaned[k] = cleanWidgetsRecursive(nestedWidgets)
2136						continue
2137					}
2138				}
2139				// Recursively clean groups (which contain widgets)
2140				if k == "groups" {
2141					if groups, ok := v.([]interface{}); ok {
2142						cleanedGroups := make([]interface{}, 0, len(groups))
2143						for _, g := range groups {
2144							if group, ok := g.(map[string]interface{}); ok {
2145								cleanedGroup := make(map[string]interface{})
2146								for gk, gv := range group {
2147									if gk == "widgets" {
2148										if groupWidgets, ok := gv.([]interface{}); ok {
2149											cleanedGroup[gk] = cleanWidgetsRecursive(groupWidgets)
2150											continue
2151										}
2152									}
2153									cleanedGroup[gk] = gv
2154								}
2155								cleanedGroups = append(cleanedGroups, cleanedGroup)
2156							} else {
2157								cleanedGroups = append(cleanedGroups, g)
2158							}
2159						}
2160						cleaned[k] = cleanedGroups
2161						continue
2162					}
2163				}
2164				cleaned[k] = v
2165			}
2166	
2167			// Fix table-entities-explorer widgets that have dataset but no blueprint
2168			// The API requires either a blueprint property or a blueprint rule in the dataset
2169			widgetType, _ := cleaned["type"].(string)
2170			if widgetType == "table-entities-explorer" {
2171				_, hasBlueprint := cleaned["blueprint"]
2172				_, hasDataset := cleaned["dataset"]
2173				if hasDataset && !hasBlueprint {
2174					// Add empty blueprint to indicate cross-blueprint dataset query
2175					cleaned["blueprint"] = ""
2176				}
2177			}
2178	
2179			result = append(result, cleaned)
2180		}
2181		return result
2182	}
