2184	// mergeWidgetAgentIdentifiers copies agentIdentifier from existing widgets to new widgets.
2185	// This is needed because the API now requires agentIdentifier on certain widget types,
2186	// but exported data may not have it.
2187	func mergeWidgetAgentIdentifiers(newWidgets, existingWidgets []interface{}) []interface{} {
2188		// Build a map of existing widgets by ID for quick lookup
2189		existingByID := make(map[string]map[string]interface{})
2190		for _, w := range existingWidgets {
2191			if widget, ok := w.(map[string]interface{}); ok {
2192				if id, ok := widget["id"].(string); ok && id != "" {
2193					existingByID[id] = widget
2194				}
2195			}
2196		}
2197	
2198		result := make([]interface{}, 0, len(newWidgets))
2199		for idx, w := range newWidgets {
2200			widget, ok := w.(map[string]interface{})
2201			if !ok {
2202				result = append(result, w)
2203				continue
2204			}
2205	
2206			// Try to find matching existing widget by ID
2207			var existingWidget map[string]interface{}
2208			if id, ok := widget["id"].(string); ok && id != "" {
2209				existingWidget = existingByID[id]
2210			}
2211			// Fallback to index-based matching if no ID match
2212			if existingWidget == nil && idx < len(existingWidgets) {
2213				if ew, ok := existingWidgets[idx].(map[string]interface{}); ok {
2214					existingWidget = ew
2215				}
2216			}
2217	
2218			// Copy agentIdentifier from existing widget if present and not in new widget
2219			if existingWidget != nil {
2220				if agentID, ok := existingWidget["agentIdentifier"]; ok {
2221					if _, hasAgentID := widget["agentIdentifier"]; !hasAgentID {
2222						widget["agentIdentifier"] = agentID
2223					}
2224				}
2225			}
2226	
2227			// Recursively merge nested widgets
2228			if newNestedWidgets, ok := widget["widgets"].([]interface{}); ok {
2229				var existingNestedWidgets []interface{}
2230				if existingWidget != nil {
2231					existingNestedWidgets, _ = existingWidget["widgets"].([]interface{})
2232				}
2233				if existingNestedWidgets != nil {
2234					widget["widgets"] = mergeWidgetAgentIdentifiers(newNestedWidgets, existingNestedWidgets)
2235				}
2236			}
2237	
2238			// Recursively merge groups
2239			if newGroups, ok := widget["groups"].([]interface{}); ok {
2240				var existingGroups []interface{}
2241				if existingWidget != nil {
2242					existingGroups, _ = existingWidget["groups"].([]interface{})
2243				}
2244				if existingGroups != nil {
2245					widget["groups"] = mergeGroupAgentIdentifiers(newGroups, existingGroups)
2246				}
2247			}
2248	
2249			result = append(result, widget)
2250		}
2251		return result
2252	}
2253	
2254	// mergeGroupAgentIdentifiers merges agentIdentifier for widgets within groups.
2255	func mergeGroupAgentIdentifiers(newGroups, existingGroups []interface{}) []interface{} {
2256		// Build a map of existing groups by title for matching
2257		existingByTitle := make(map[string]map[string]interface{})
2258		for _, g := range existingGroups {
2259			if group, ok := g.(map[string]interface{}); ok {
2260				if title, ok := group["title"].(string); ok && title != "" {
2261					existingByTitle[title] = group
2262				}
2263			}
2264		}
2265	
2266		result := make([]interface{}, 0, len(newGroups))
2267		for idx, g := range newGroups {
2268			group, ok := g.(map[string]interface{})
2269			if !ok {
2270				result = append(result, g)
2271				continue
2272			}
2273	
2274			// Try to find matching existing group by title
2275			var existingGroup map[string]interface{}
2276			if title, ok := group["title"].(string); ok && title != "" {
2277				existingGroup = existingByTitle[title]
2278			}
2279			// Fallback to index-based matching
2280			if existingGroup == nil && idx < len(existingGroups) {
2281				if eg, ok := existingGroups[idx].(map[string]interface{}); ok {
2282					existingGroup = eg
2283				}
2284			}
2285	
2286			// Recursively merge widgets within the group
2287			if newWidgets, ok := group["widgets"].([]interface{}); ok {
2288				var existingWidgets []interface{}
2289				if existingGroup != nil {
2290					existingWidgets, _ = existingGroup["widgets"].([]interface{})
2291				}
2292				if existingWidgets != nil {
2293					group["widgets"] = mergeWidgetAgentIdentifiers(newWidgets, existingWidgets)
2294				}
2295			}
2296	
2297			result = append(result, group)
2298		}
2299		return result
2300	}
2301	
2302	// importIntegrations imports integrations (update config only).
2303	func (i *Importer) importIntegrations(ctx context.Context, integrations []api.Integration, result *Result, pool *WorkerPool) {
2304		for _, integration := range integrations {
2305			integration := integration
2306			pool.Go(func() {
2307				integrationID, ok := integration["identifier"].(string)
2308				if !ok || integrationID == "" {
2309					i.errors.Add(fmt.Errorf("integration is missing identifier field, skipping"), "integration", "<unknown>")
2310					return
2311				}
2312	
2313				// The integration config endpoint expects {"config": {...}} wrapper
2314				config, ok := integration["config"].(map[string]interface{})
2315				if !ok || config == nil {
2316					// No config to update — report so the user knows this integration was skipped
2317					i.errors.Add(fmt.Errorf("integration has no config field to update, skipping"), "integration", integrationID)
2318					return
2319				}
2320	
2321				// Wrap the config in the expected format
2322				payload := map[string]interface{}{
2323					"config": config,
2324				}
2325	
2326				_, err := i.client.UpdateIntegrationConfig(ctx, integrationID, payload)
2327	
2328				i.mu.Lock()
2329				if err != nil {
2330					i.errors.Add(err, "integration", integrationID)
2331				} else {
2332					result.IntegrationsUpdated++
2333				}
2334				i.mu.Unlock()
2335			})
2336		}
2337	}
2338	
2339	// importPermissions applies blueprint and action permission changes from a DiffResult.
2340	// Permissions are applied after all other resources have been imported so that the
2341	// underlying blueprints and actions are guaranteed to exist.
2342	func (i *Importer) importPermissions(ctx context.Context, diff *DiffResult) {
2343		if diff == nil {
2344			return
2345		}
2346	
2347		// Import blueprint permissions
2348		for _, change := range diff.BlueprintPermissions {
2349			if _, err := i.client.UpdateBlueprintPermissions(ctx, change.Identifier, change.Permissions); err != nil {
2350				i.errors.Add(fmt.Errorf("failed to update blueprint permissions for %s: %w", change.Identifier, err), "blueprint_permissions", change.Identifier)
2351			}
2352		}
2353	
2354		// Import action permissions
2355		for _, change := range diff.ActionPermissions {
2356			if _, err := i.client.UpdateActionPermissions(ctx, change.Identifier, change.Permissions); err != nil {
2357				i.errors.Add(fmt.Errorf("failed to update action permissions for %s: %w", change.Identifier, err), "action_permissions", change.Identifier)
2358			}
2359		}
2360	}
2361	
2362	// applyDataExclusion filters data in-place before diffing/importing.
2363	// excludeDeep removes the blueprint schema AND all its entities/scorecards/actions.
2364	// excludeSchema removes only the blueprint schema; resources for that blueprint are kept.
2365	func applyDataExclusion(data *export.Data, excludeDeep, excludeSchema []string, skipSystemBlueprints bool) {
2366		// Pre-pass: remove system blueprint schemas and their entities (shallow skip).
2367		// Scorecards, actions, and permissions are kept.
2368		if skipSystemBlueprints {
2369			filteredBPs := data.Blueprints[:0:0]
2370			for _, bp := range data.Blueprints {
2371				id, _ := bp["identifier"].(string)
2372				if strings.HasPrefix(id, "_") {
2373					continue
2374				}
2375				filteredBPs = append(filteredBPs, bp)
2376			}
2377			data.Blueprints = filteredBPs
2378	
2379			filteredEnts := data.Entities[:0:0]
2380			for _, e := range data.Entities {
2381				bpID, _ := e["blueprint"].(string)
2382				if strings.HasPrefix(bpID, "_") {
2383					continue
2384				}
2385				filteredEnts = append(filteredEnts, e)
2386			}
2387			data.Entities = filteredEnts
2388		}
2389	
2390		if len(excludeDeep) == 0 && len(excludeSchema) == 0 {
2391			return
2392		}
2393		deepSet := make(map[string]bool, len(excludeDeep))
2394		for _, id := range excludeDeep {
2395			deepSet[id] = true
2396		}
2397		schemaSet := make(map[string]bool, len(excludeSchema))
2398		for _, id := range excludeSchema {
2399			schemaSet[id] = true
2400		}
2401	
2402		// Filter blueprints (both deep and schema-only remove the blueprint record)
2403		filtered := data.Blueprints[:0:0]
2404		for _, bp := range data.Blueprints {
2405			id, _ := bp["identifier"].(string)
2406			if deepSet[id] || schemaSet[id] {
2407				continue
2408			}
2409			filtered = append(filtered, bp)
2410		}
2411		data.Blueprints = filtered
2412	
2413		// Filter entities — only deep exclusion removes them
2414		filteredEntities := data.Entities[:0:0]
2415		for _, e := range data.Entities {
2416			bpID, _ := e["blueprint"].(string)
2417			if deepSet[bpID] {
2418				continue
2419			}
2420			filteredEntities = append(filteredEntities, e)
2421		}
2422		data.Entities = filteredEntities
2423	
2424		// Filter scorecards — only deep exclusion removes them
2425		filteredScorecards := data.Scorecards[:0:0]
2426		for _, sc := range data.Scorecards {
2427			bpID, _ := sc["blueprintIdentifier"].(string)
2428			if deepSet[bpID] {
2429				continue
2430			}
2431			filteredScorecards = append(filteredScorecards, sc)
2432		}
2433		data.Scorecards = filteredScorecards
2434	
2435		// Track action IDs for deep-excluded blueprints so we can clean up ActionPermissions
2436		excludedActionIDs := make(map[string]bool)
2437		for _, a := range data.Actions {
2438			bpID, _ := a["blueprint"].(string)
2439			if deepSet[bpID] {
2440				if actionID, _ := a["identifier"].(string); actionID != "" {
2441					excludedActionIDs[actionID] = true
2442				}
2443			}
2444		}
2445	
2446		// Filter actions — only deep exclusion removes them
2447		filteredActions := data.Actions[:0:0]
2448		for _, a := range data.Actions {
2449			bpID, _ := a["blueprint"].(string)
2450			if deepSet[bpID] {
2451				continue
2452			}
2453			filteredActions = append(filteredActions, a)
2454		}
2455		data.Actions = filteredActions
2456	
2457		// Clean up blueprint permissions for deep exclusions
2458		for id := range deepSet {
2459			delete(data.BlueprintPermissions, id)
2460		}
2461	
2462		// Clean up action permissions for deep exclusions
2463		if data.ActionPermissions != nil {
2464			for id := range excludedActionIDs {
2465				delete(data.ActionPermissions, id)
2466			}
2467		}
2468	}
