1	package import_module
2	
3	import (
4		"regexp"
5		"strings"
6	
7		"github.com/port-experimental/port-cli/internal/api"
8	)
9	
10	// DependentFields are blueprint fields that may reference other blueprints.
11	// Note: "relations" is NOT included because the relation schema must be created
12	// with the blueprint - you can't add relations to a blueprint after creation.
13	// The topological sort ensures relation targets exist before blueprint creation.
14	var DependentFields = []string{
15		"mirrorProperties",
16		"calculationProperties",
17		"aggregationProperties",
18		// ownership with type "Inherited" references a relation path (e.g. "service.$identifier").
19		// Port validates the path at create/update time, so this must be applied after relations exist.
20		"ownership",
21	}
22	
23	// ExtractRelations extracts the relations field from a blueprint.
24	func ExtractRelations(bp api.Blueprint) map[string]interface{} {
25		relations, ok := bp["relations"].(map[string]interface{})
26		if !ok {
27			return nil
28		}
29		return relations
30	}
31	
32	// StripRelations creates a copy of the blueprint without the relations field.
33	func StripRelations(bp api.Blueprint) api.Blueprint {
34		stripped := make(api.Blueprint)
35		for k, v := range bp {
36			if k != "relations" {
37				stripped[k] = v
38			}
39		}
40		return stripped
41	}
42	
43	// ExtractDependentFields extracts all dependent fields from a blueprint.
44	// Returns a map of field name to field value for fields that were present.
45	func ExtractDependentFields(bp api.Blueprint) map[string]interface{} {
46		extracted := make(map[string]interface{})
47		for _, field := range DependentFields {
48			if val, ok := bp[field]; ok && val != nil {
49				extracted[field] = val
50			}
51		}
52		return extracted
53	}
54	
55	// StripDependentFields creates a copy of the blueprint without any dependent fields.
56	func StripDependentFields(bp api.Blueprint) api.Blueprint {
57		stripped := make(api.Blueprint)
58		fieldSet := make(map[string]bool)
59		for _, f := range DependentFields {
60			fieldSet[f] = true
61		}
62	
63		for k, v := range bp {
64			if !fieldSet[k] {
65				stripped[k] = v
66			}
67		}
68		return stripped
69	}
70	
71	// IsRelationError checks if an error is related to missing relation targets.
72	// This detects common error patterns from the Port API when a relation target doesn't exist.
73	func IsRelationError(err error) bool {
74		if err == nil {
75			return false
76		}
77	
78		errStr := strings.ToLower(err.Error())
79	
80		// More specific error patterns for relation issues to avoid false positives
81		relationErrorPatterns := []string{
82			"relation target",
83			"target blueprint",
84			"blueprint not found",
85			"invalid relation target",
86			"missing blueprint",
87			"relation does not exist",
88			"target does not exist",
89			"cannot find blueprint",
90			"blueprint identifier",
91			"relation reference",
92			// Inherited ownership path references a relation; strip ownership and retry once relations exist.
93			"invalid_inherited_ownership_path",
94			"path entered",
95			"missingrelation",
96		}
97	
98		// Also check for generic patterns but only if they appear in context
99		genericPatterns := []string{
100			"relation",
101			"target",
102		}
103	
104		// First check specific patterns
105		for _, pattern := range relationErrorPatterns {
106			if strings.Contains(errStr, pattern) {
107				return true
108			}
109		}
110	
111		// Then check generic patterns but require additional context
112		for _, pattern := range genericPatterns {
113			if strings.Contains(errStr, pattern) {
114				if strings.Contains(errStr, "blueprint") || strings.Contains(errStr, "relation") {
115					return true
116				}
117			}
118		}
119	
120		return false
121	}
122	
123	// GetAllDependencies extracts all blueprint identifiers that this blueprint depends on.
124	// This includes targets from relations, mirrorProperties, calculationProperties, and aggregationProperties.
125	func GetAllDependencies(bp api.Blueprint) []string {
126		deps := make(map[string]bool)
127	
128		// Get relation targets
129		for _, target := range getRelationTargets(bp) {
130			deps[target] = true
131		}
132	
133		// Get mirror property targets
134		for _, target := range getMirrorPropertyTargets(bp) {
135			deps[target] = true
136		}
137	
138		// Get calculation property targets
139		for _, target := range getCalculationPropertyTargets(bp) {
140			deps[target] = true
141		}
142	
143		// Get aggregation property targets
144		for _, target := range getAggregationPropertyTargets(bp) {
145			deps[target] = true
146		}
147	
148		// Convert to slice
149		result := make([]string, 0, len(deps))
150		for dep := range deps {
151			result = append(result, dep)
152		}
153		return result
154	}
155	
156	// getRelationTargets extracts all relation target blueprint identifiers from a blueprint.
157	func getRelationTargets(bp api.Blueprint) []string {
158		targets := []string{}
159		relations, ok := bp["relations"].(map[string]interface{})
160		if !ok {
161			return targets
162		}
163	
164		for _, relation := range relations {
165			relationMap, ok := relation.(map[string]interface{})
166			if !ok {
167				continue
168			}
169	
170			target, ok := relationMap["target"].(string)
171			if ok && target != "" {
172				targets = append(targets, target)
173			}
174		}
175	
176		return targets
177	}
178	
179	// getMirrorPropertyTargets extracts blueprint identifiers from mirror properties.
180	// Mirror properties have a "path" field like "relationName.propertyName" where
181	// relationName refers to a relation whose target is another blueprint.
182	func getMirrorPropertyTargets(bp api.Blueprint) []string {
183		targets := []string{}
184		mirrorProps, ok := bp["mirrorProperties"].(map[string]interface{})
185		if !ok {
186			return targets
187		}
188	
189		// Build map of relation name -> target blueprint
190		relationTargets := make(map[string]string)
191		relations, ok := bp["relations"].(map[string]interface{})
192		if ok {
193			for relName, rel := range relations {
194				relMap, ok := rel.(map[string]interface{})
195				if !ok {
196					continue
197				}
198				if target, ok := relMap["target"].(string); ok {
199					relationTargets[relName] = target
200				}
201			}
202		}
203	
204		// For each mirror property, find the target blueprint via the relation
205		for _, prop := range mirrorProps {
206			propMap, ok := prop.(map[string]interface{})
207			if !ok {
208				continue
209			}
210	
211			path, ok := propMap["path"].(string)
212			if !ok || path == "" {
213				continue
214			}
215	
216			// Path format: "relationName.propertyName" or "relationName.nestedRelation.property"
217			parts := strings.Split(path, ".")
218			if len(parts) >= 1 {
219				relName := parts[0]
220				if target, ok := relationTargets[relName]; ok {
221					targets = append(targets, target)
222				}
223			}
224		}
225	
226		return targets
227	}
228	
229	// getCalculationPropertyTargets extracts blueprint identifiers from calculation properties.
230	// Calculation formulas may reference other blueprints via relations.
231	func getCalculationPropertyTargets(bp api.Blueprint) []string {
232		targets := []string{}
233		calcProps, ok := bp["calculationProperties"].(map[string]interface{})
234		if !ok {
235			return targets
236		}
237	
238		// Build map of relation name -> target blueprint
239		relationTargets := make(map[string]string)
240		relations, ok := bp["relations"].(map[string]interface{})
241		if ok {
242			for relName, rel := range relations {
243				relMap, ok := rel.(map[string]interface{})
244				if !ok {
245					continue
246				}
247				if target, ok := relMap["target"].(string); ok {
248					relationTargets[relName] = target
249				}
