388	// TopologicalSort sorts blueprints in dependency order using Kahn's algorithm.
389	// Returns blueprints grouped by dependency level (level 0 has no dependencies, etc.)
390	// Also returns any blueprints involved in cycles (which couldn't be sorted).
391	func TopologicalSort(blueprints []api.Blueprint, existingBlueprints map[string]bool) ([][]api.Blueprint, []api.Blueprint) {
392		// Build identifier -> blueprint map
393		bpMap := make(map[string]api.Blueprint)
394		for _, bp := range blueprints {
395			id, ok := bp["identifier"].(string)
396			if !ok || id == "" {
397				continue
398			}
399			bpMap[id] = bp
400		}
401	
402		// Build dependency graph
403		// inDegree[id] = number of dependencies this blueprint has (that are in our set)
404		// dependents[id] = blueprints that depend on this one
405		inDegree := make(map[string]int)
406		dependents := make(map[string][]string)
407	
408		for id := range bpMap {
409			inDegree[id] = 0
410			dependents[id] = []string{}
411		}
412	
413		for id, bp := range bpMap {
414			deps := GetAllDependencies(bp)
415			for _, dep := range deps {
416				// Only count dependencies that are in our blueprint set
417				// (not system blueprints or already existing ones)
418				if _, inSet := bpMap[dep]; inSet {
419					inDegree[id]++
420					dependents[dep] = append(dependents[dep], id)
421				}
422			}
423		}
424	
425		// Kahn's algorithm
426		var levels [][]api.Blueprint
427		processed := make(map[string]bool)
428	
429		for len(processed) < len(bpMap) {
430			// Find all blueprints with no remaining dependencies
431			var currentLevel []api.Blueprint
432			for id, degree := range inDegree {
433				if degree == 0 && !processed[id] {
434					currentLevel = append(currentLevel, bpMap[id])
435					processed[id] = true
436				}
437			}
438	
439			// If no blueprints can be processed, we have a cycle
440			if len(currentLevel) == 0 {
441				break
442			}
443	
444			levels = append(levels, currentLevel)
445	
446			// Reduce in-degree for dependents
447			for _, bp := range currentLevel {
448				id := bp["identifier"].(string)
449				for _, dependent := range dependents[id] {
450					inDegree[dependent]--
451				}
452			}
453		}
454	
455		// Collect any blueprints in cycles (not processed)
456		var cyclic []api.Blueprint
457		for id, bp := range bpMap {
458			if !processed[id] {
459				cyclic = append(cyclic, bp)
460			}
461		}
462	
463		return levels, cyclic
464	}
