467	// Blueprints with direct ownership are in the first level. Blueprints with inherited ownership depend
468	// on the target blueprint of the first relation segment in their ownership path.
469	func TopologicalSortOwnership(blueprints []api.Blueprint) ([][]api.Blueprint, []api.Blueprint) {
470		bpMap := make(map[string]api.Blueprint)
471		for _, bp := range blueprints {
472			id, ok := bp["identifier"].(string)
473			if !ok || id == "" {
474				continue
475			}
476			if _, hasOwnership := bp["ownership"]; !hasOwnership {
477				continue
478			}
479			bpMap[id] = bp
480		}
481	
482		inDegree := make(map[string]int)
483		dependents := make(map[string][]string)
484		for id := range bpMap {
485			inDegree[id] = 0
486			dependents[id] = []string{}
487		}
488	
489		for id, bp := range bpMap {
490			dep := getOwnershipDependency(bp)
491			if dep == "" {
492				continue
493			}
494			if _, inSet := bpMap[dep]; inSet {
495				inDegree[id]++
496				dependents[dep] = append(dependents[dep], id)
497			}
498		}
499	
500		var levels [][]api.Blueprint
501		processed := make(map[string]bool)
502	
503		for len(processed) < len(bpMap) {
504			var currentLevel []api.Blueprint
505			for id, degree := range inDegree {
506				if degree == 0 && !processed[id] {
507					currentLevel = append(currentLevel, bpMap[id])
508					processed[id] = true
509				}
510			}
511	
512			if len(currentLevel) == 0 {
513				break
514			}
515	
516			levels = append(levels, currentLevel)
517			for _, bp := range currentLevel {
518				id := bp["identifier"].(string)
519				for _, dependent := range dependents[id] {
520					inDegree[dependent]--
521				}
522			}
523		}
524	
525		var cyclic []api.Blueprint
526		for id, bp := range bpMap {
527			if !processed[id] {
528				cyclic = append(cyclic, bp)
529			}
530		}
531	
532		return levels, cyclic
533	}
